'use client'

import React from 'react'
import Link from 'next/link'
import { GlassCard } from '../ui'

interface NewsCardProps {
  id: string
  title: string
  excerpt?: string
  category: string
  date: string
  author?: string
  authorAvatar?: string
  views: string
  comments: number
  thumbnail?: string
  featured?: boolean
  badge?: 'FEATURED' | 'NEWS' | 'OFFICIAL' | 'GAMEPLAY' | 'COMMUNITY' | 'UPDATES'
}

const NewsCard: React.FC<NewsCardProps> = ({
  id,
  title,
  excerpt,
  category,
  date,
  author,
  authorAvatar,
  views,
  comments,
  thumbnail,
  featured = false,
  badge
}) => {
  // Cyberpunk gradient backgrounds for placeholders
  const gradients = [
    'linear-gradient(135deg, #ff006e 0%, #8b00ff 100%)',
    'linear-gradient(135deg, #8b00ff 0%, #00d9ff 100%)',
    'linear-gradient(135deg, #00d9ff 0%, #ff006e 100%)',
    'linear-gradient(135deg, #ff00ff 0%, #ff006e 100%)',
  ]

  const randomGradient = gradients[Math.floor(Math.random() * gradients.length)]

  const badgeColors = {
    FEATURED: 'bg-neon-pink',
    NEWS: 'bg-neon-purple',
    OFFICIAL: 'bg-neon-blue',
    GAMEPLAY: 'bg-neon-magenta',
    COMMUNITY: 'bg-purple-600',
    UPDATES: 'bg-blue-600'
  }

  return (
    <Link href={`/news/${id}`}>
      <GlassCard 
        variant="default" 
        blur="medium" 
        className={`
          group cursor-pointer overflow-hidden transition-all duration-300
          hover:scale-[1.02] hover:neon-glow-pink
          ${featured ? 'col-span-2 row-span-2' : ''}
        `}
      >
        {/* Thumbnail */}
        <div className="relative aspect-video overflow-hidden">
          {thumbnail ? (
            <img 
              src={thumbnail} 
              alt={title}
              className="w-full h-full object-cover transition-transform duration-300 group-hover:scale-110"
            />
          ) : (
            <div 
              className="w-full h-full"
              style={{ background: randomGradient }}
            >
              {/* Overlay pattern */}
              <div className="absolute inset-0 opacity-20" style={{
                backgroundImage: `repeating-linear-gradient(
                  45deg,
                  transparent,
                  transparent 10px,
                  rgba(255,255,255,0.1) 10px,
                  rgba(255,255,255,0.1) 20px
                )`
              }} />
            </div>
          )}

          {/* Badge */}
          {badge && (
            <div className={`
              absolute top-4 left-4 px-3 py-1 rounded-md text-xs font-bold text-white
              ${badgeColors[badge]}
            `}>
              {badge}
            </div>
          )}

          {/* Date */}
          <div className="absolute top-4 right-4 px-3 py-1 glass-heavy rounded-md text-xs text-white">
            {date}
          </div>
        </div>

        {/* Content */}
        <div className="p-6">
          {/* Category */}
          <div className="text-neon-purple text-xs font-semibold mb-2 uppercase tracking-wider">
            {category}
          </div>

          {/* Title */}
          <h3 className={`
            font-bold text-white mb-3 line-clamp-2
            group-hover:text-transparent group-hover:bg-clip-text 
            group-hover:bg-gradient-to-r group-hover:from-neon-pink group-hover:to-neon-purple
            transition-all duration-300
            ${featured ? 'text-2xl' : 'text-lg'}
          `}>
            {title}
          </h3>

          {/* Excerpt (only for featured) */}
          {featured && excerpt && (
            <p className="text-gray-400 text-sm mb-4 line-clamp-2">
              {excerpt}
            </p>
          )}

          {/* Meta */}
          <div className="flex items-center justify-between text-sm text-gray-400">
            <div className="flex items-center gap-4">
              {/* Author */}
              {author && (
                <div className="flex items-center gap-2">
                  {authorAvatar ? (
                    <img 
                      src={authorAvatar} 
                      alt={author}
                      className="w-6 h-6 rounded-full"
                    />
                  ) : (
                    <div className="w-6 h-6 rounded-full bg-gradient-to-br from-neon-pink to-neon-purple flex items-center justify-center text-xs text-white">
                      {author.charAt(0)}
                    </div>
                  )}
                  <span className="text-xs">{author}</span>
                </div>
              )}

              {/* Views */}
              <div className="flex items-center gap-1">
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" />
                </svg>
                <span>{views}</span>
              </div>

              {/* Comments */}
              <div className="flex items-center gap-1">
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72C3.512 15.042 3 13.574 3 12c0-4.418 4.03-8 9-8s9 3.582 9 8z" />
                </svg>
                <span>{comments}</span>
              </div>
            </div>

            {/* Share */}
            <button className="p-2 hover:bg-gray-800 rounded-lg transition-colors">
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8.684 13.342C8.886 12.938 9 12.482 9 12c0-.482-.114-.938-.316-1.342m0 2.684a3 3 0 110-2.684m0 2.684l6.632 3.316m-6.632-6l6.632-3.316m0 0a3 3 0 105.367-2.684 3 3 0 00-5.367 2.684zm0 9.316a3 3 0 105.368 2.684 3 3 0 00-5.368-2.684z" />
              </svg>
            </button>
          </div>
        </div>
      </GlassCard>
    </Link>
  )
}

export default NewsCard

